catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading || newValue == '') {
        return;
    }
    g_form.clearMessages();

    // 1. Parse the newly selected End Date
    var endString = newValue.split(' ')[0]; 
    var endParts = endString.split('-');
    var selectedEndDate = new Date(parseInt(endParts[0], 10), parseInt(endParts[1], 10) - 1, parseInt(endParts[2], 10));

    // 2. Get the Start Date value from the form
    var startDateValue = g_form.getValue('start_date'); 

    // 3. If Start Date is empty, you can either force them to fill it out, or just check against Today
    if (startDateValue == '') {
        var today = new Date();
        today.setHours(0, 0, 0, 0);
        if (selectedEndDate <= today) {
            g_form.addErrorMessage('The End Date must be in the future.');
            g_form.clearValue('end_date');
        }
        return; 
    }

    // 4. Parse the existing Start Date
    var startString = startDateValue.split(' ')[0];
    var startParts = startString.split('-');
    var selectedStartDate = new Date(parseInt(startParts[0], 10), parseInt(startParts[1], 10) - 1, parseInt(startParts[2], 10));

    // 5. Compare: End Date must be ahead of Start Date
    if (selectedEndDate <= selectedStartDate) {
        g_form.addErrorMessage('The End Date must be after the Start Date.');
        g_form.clearValue('end_date');
    }
}
